# application.yml - Configurar rutas
spring:
  cloud:
    gateway:
      routes:
        # Customer Service
        - id: customer-service
          uri: lb://CUSTOMER-SERVICE
          predicates:
            - Path=/api/v1/customer/**
          filters:
            - StripPrefix=0

        # Product Service
        - id: product-service
          uri: lb://PRODUCT-SERVICE
          predicates:
            - Path=/api/v1/product/**

        # Transaction Service
        - id: transaction-service
          uri: lb://TRANSACTION-SERVICE
          predicates:
            - Path=/api/v1/transaction/**

        # Eureka Dashboard
        - id: eureka-server
          uri: lb://EUREKA-SERVER
          predicates:
            - Path=/eureka/**

        # Admin Server
        - id: admin-server
          uri: lb://ADMIN-SERVER
          predicates:
            - Path=/admin/**

// LoggingGlobalFilter.java
package com.paymentchange.apigateway.filter;

import lombok.extern.slf4j.Slf4j;
import org.springframework.cloud.gateway.filter.GatewayFilterChain;
import org.springframework.cloud.gateway.filter.GlobalFilter;
import org.springframework.core.Ordered;
import org.springframework.http.server.reactive.ServerHttpRequest;
import org.springframework.http.server.reactive.ServerHttpResponse;
import org.springframework.stereotype.Component;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

@Slf4j
@Component
public class LoggingGlobalFilter implements GlobalFilter, Ordered {

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, 
                            GatewayFilterChain chain) {

        ServerHttpRequest request = exchange.getRequest();

        // Pre-filter: logging antes de enviar a backend
        log.info("[PRE-FILTER] Request: {} {}", 
                request.getMethod(), 
                request.getURI());
        log.info("[PRE-FILTER] Headers: {}", request.getHeaders());

        long startTime = System.currentTimeMillis();

        // Continuar cadena y agregar post-filter
        return chain.filter(exchange)
            .then(Mono.fromRunnable(() -> {
                ServerHttpResponse response = exchange.getResponse();
                long duration = System.currentTimeMillis() - startTime;

                // Post-filter: logging después de recibir response
                log.info("[POST-FILTER] Response Status: {}", 
                        response.getStatusCode());
                log.info("[POST-FILTER] Duration: {}ms", duration);
            }));
    }

    @Override
    public int getOrder() {
        return -1;  // Alta prioridad (ejecuta primero)
    }
}

// AuthenticationFilter.java - Ejemplo filter autenticación
@Slf4j
@Component
public class AuthenticationFilter implements GlobalFilter, Ordered {

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, 
                            GatewayFilterChain chain) {

        ServerHttpRequest request = exchange.getRequest();

        // Verificar header Authorization
        if (!request.getHeaders().containsKey("Authorization")) {
            log.error("Missing Authorization header");

            exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
            return exchange.getResponse().setComplete();
        }

        String authHeader = request.getHeaders()
            .getFirst("Authorization");

        // Validar token (ejemplo simple)
        if (!isValidToken(authHeader)) {
            log.error("Invalid token");
            exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
            return exchange.getResponse().setComplete();
        }

        log.info("Authentication successful");
        return chain.filter(exchange);
    }

    private boolean isValidToken(String token) {
        // Implementar validación real (JWT, OAuth2)
        return token != null && token.startsWith("Basic ");
    }

    @Override
    public int getOrder() {
        return 0;  // Ejecuta después de logging
    }
}

